// embedding を取り出し、モード別に Pinecone クエリを整形
// mode: zodiac=星座 / element=エレメント / quality=クオリティ / topic=知りたいことのみ
// 各モードとも該当属性に厳密一致するコンテンツのみ通す（属性をまたぐフォールバックなし）
const embedding = $input.first().json.data[0].embedding;
const body = $('Webhook').first().json.body || {};
const mode = body.mode || 'zodiac';
const userZodiac = body.zodiac || '';
const userElement = body.element || '';
const userQuality = body.quality || '';

const query = {
  vector: embedding,
  topK: 100,
  includeMetadata: true
};

if (mode === 'zodiac' && userZodiac) {
  query.filter = { zodiac: { '$in': [userZodiac] } };
} else if (mode === 'element' && userElement) {
  query.filter = { element: { '$in': [userElement] } };
} else if (mode === 'quality' && userQuality) {
  query.filter = { quality: { '$in': [userQuality] } };
}
// mode === 'topic' はフィルタなし（知りたいことのみ）

return [{ json: query }];

// Pinecone でフィルタ済みのマッチをカテゴリ別に上位2件ずつ選択（合計6件）
// 全モード共通: 該当属性で絞り込み済みのため、類似度順に詰めるだけ
const matches = $input.first().json.matches || [];

const categories = ['newsletter', 'podcast', 'paid_product'];
const perCategory = {};
categories.forEach(c => perCategory[c] = []);

const toArr = (v) => {
  if (Array.isArray(v)) return v;
  if (v === undefined || v === null) return [''];
  return [String(v)];
};

const toResult = (match) => {
  const elArr = toArr(match.metadata?.element).filter(s => s !== '');
  const zoArr = toArr(match.metadata?.zodiac).filter(s => s !== '');
  const quArr = toArr(match.metadata?.quality).filter(s => s !== '');
  return {
    id: match.id,
    score: match.score,
    title: match.metadata?.title || '',
    body: match.metadata?.body || '',
    url: match.metadata?.url || '',
    category: match.metadata?.category || 'unknown',
    zodiac: zoArr.join(','),
    element: elArr.join(','),
    quality: quArr.join(','),
    audio_url: match.metadata?.audio_url || ''
  };
};

const pushIfRoom = (match) => {
  const cat = match.metadata?.category;
  if (!perCategory[cat]) return false;
  if (perCategory[cat].length >= 2) return false;
  if (perCategory[cat].some(x => x.id === match.id)) return false;
  perCategory[cat].push(toResult(match));
  return true;
};

for (const match of matches) {
  pushIfRoom(match);
}

const results = [
  ...perCategory.newsletter,
  ...perCategory.podcast,
  ...perCategory.paid_product
];

return [{ json: { results } }];

// 検索ログ用のデータを準備
const body = $input.first().json.body || {};
const query = body.query || '';
const zodiac = body.zodiac || '';
const element = body.element || '';

// 日本時間 (JST = UTC+9) でタイムスタンプ生成
const now = new Date();
const jst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const timestamp = jst.toISOString()
  .replace('T', ' ')
  .replace(/\.\d{3}Z$/, '')
  .replace(/-/g, '/');

return [{ json: { timestamp, query, zodiac, element } }];
